Bash(node -e "
const fs = require\('fs'\);
const dir = './src/content/doctors';
const files = fs.readdirSync\(dir\).filter\(f => f.endsWith\('.json'\)\);
let nullIssuing = 0;
let zeroYear = 0;
let total = 0;
for \(const file of files\) {
  const data = JSON.parse\(fs.readFileSync\(dir + '/' + file, 'utf-8'\)\);
  if \(data.awards\) {
    for \(const a of data.awards\) {
      total++;
      if \(!a.issuingBody\) nullIssuing++;
      if \(!a.year\) zeroYear++;
    }
  }
}
console.log\('Total awards:', total\);
console.log\('Awards with null issuingBody:', nullIssuing\);
console.log\('Awards with no year:', zeroYear\);
" 2>&1)

Bash(node -e "
const fs = require\('fs'\);
const dir = './src/content/doctors';
const files = fs.readdirSync\(dir\).filter\(f => f.endsWith\('.json'\)\);
let issues = [];
for \(const file of files\) {
  const data = JSON.parse\(fs.readFileSync\(dir + '/' + file, 'utf-8'\)\);
  if \(!data.fullName\) issues.push\(file + ': missing fullName'\);
  if \(!data.specialty\) issues.push\(file + ': missing specialty'\);
  if \(!data.geography?.country\) issues.push\(file + ': missing geography.country'\);
  if \(data.timeline\) {
    for \(const t of data.timeline\) {
      if \(!t.year\) { issues.push\(file + ': timeline entry missing year'\); break; }
      if \(!t.title\) { issues.push\(file + ': timeline entry missing title'\); break; }
    }
  }
  if \(data.techniquesInvented\) {
    for \(const t of data.techniquesInvented\) {
      if \(!t\) { issues.push\(file + ': empty technique name'\); break; }
    }
  }
}
console.log\('Issues found:', issues.length\);
issues.slice\(0,20\).forEach\(i => console.log\(' -', i\)\);
" 2>&1)

